function djb2Hash(str) {
  let hash = 5381;
  for (let i = 0; i < str.length; i++) {
    hash = (hash << 5) + hash + str.charCodeAt(i);
    hash = hash & 0xffffffff;
  }
  return (hash >>> 0).toString(16).padStart(8, "0");
}

function randomHex(bytes) {
  let out = "";
  if (typeof globalThis.crypto !== "undefined" && typeof globalThis.crypto.getRandomValues === "function") {
    const arr = new Uint8Array(bytes);
    globalThis.crypto.getRandomValues(arr);
    for (const b of arr) out += b.toString(16).padStart(2, "0");
    return out;
  }
  for (let i = 0; i < bytes; i++) out += Math.floor(Math.random() * 256).toString(16).padStart(2, "0");
  return out;
}

function generateReviewToken() {
  return randomHex(16) + djb2Hash(String(Date.now()) + String(Math.random()));
}

function escapeHtml(value) {
  return String(value == null ? "" : value)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, '&#39;');
}

return items.map(item => {
  const input = item.json || {};
  const caseInput = input.case_input || {};
  const nes = caseInput.nes || {};
  const decision = caseInput.decision || {};
  const draft = caseInput.draft || {};
  const reply = nes.reply || {};

  const intakeId = String(caseInput.intake_id || nes.intake_id || "UNKNOWN_INTAKE");
  const policyVersion = caseInput.policy_version || nes.policy_version || CONFIG.policy_version;
  const caseId = "case-" + djb2Hash(intakeId + "|" + policyVersion);

  const ttlRaw = CONFIG.review.review_token_ttl_minutes;
  const ttlMinutes = (typeof ttlRaw === "number" && ttlRaw > 0) ? ttlRaw : CONFIG.review.review_token_ttl_minutes_default;

  const nowIso = new Date().toISOString();
  const expiresIso = new Date(Date.now() + ttlMinutes * 60000).toISOString();
  const token = generateReviewToken();

  const eaccount = nes.eaccount || "";
  const senderConfig = (CONFIG.sender_mapping || {})[eaccount] || null;
  const templateVariables = {
    firstName: caseInput.first_name || null,
    senderName: senderConfig ? senderConfig.sender_name : null,
    bookingLink: senderConfig ? senderConfig.booking_link : null
  };

  const templateId = decision.reply_template_id || "";
  const blockedVariables = [];
  const replyMode = decision.reply_mode || caseInput.reply_mode || "";
  const sendableMode = replyMode === "FIXED_TEMPLATE_APPROVAL" || replyMode === "AI_DRAFT_APPROVAL";
  if (sendableMode && !templateVariables.senderName) blockedVariables.push("senderName");
  if (/BOOKING|T1_SCENARIO_A|T3_/.test(templateId) && !templateVariables.bookingLink) blockedVariables.push("bookingLink");

  const sanitizedContext = {
    intake_id: intakeId,
    category: decision.category || caseInput.category || "UNKNOWN",
    confidence: caseInput.confidence ?? decision.confidence ?? null,
    urgency: caseInput.urgency || decision.priority || "routine",
    risk_flags: caseInput.risk_flags || decision.risk_flags || [],
    campaign_context: nes.campaign_context || {},
    reply_subject: reply.subject || null,
    reply_text: reply.text || null,
    reply_snippet: reply.snippet || null,
    recommended_action_plan: decision || {},
    sender_handoff: {
      nes: caseInput.nes || {},
      decision: caseInput.decision || {},
      draft: caseInput.draft || {},
      validation: caseInput.validation || {}
    }
  };

  const draftText = (draft && typeof draft.draft_text === "string") ? draft.draft_text : "";

  return {
    json: {
      ...input,
      config: CONFIG,
      review_case: {
        case_id: caseId,
        intake_id: intakeId,
        token,
        token_expires_at: expiresIso,
        status: "NEW",
        category: sanitizedContext.category,
        urgency: sanitizedContext.urgency,
        reply_mode: replyMode || "HUMAN_ONLY",
        draft_text: draftText,
        template_variables: templateVariables,
        blocked_variables: blockedVariables,
        sanitized_context: sanitizedContext,
        policy_version: policyVersion,
        kb_version: caseInput.kb_version || CONFIG.kb_version,
        notification_status: "PENDING",
        approver_identity: null,
        approved_at: null,
        final_reply_text: null,
        decision_payload: null,
        created_at: nowIso,
        updated_at: nowIso
      }
    }
  };
});

const items = $input.all();

function parseJson(value, fallback) {
  if (value === null || value === undefined || value === "") return fallback;
  if (typeof value === "object") return value;
  try { return JSON.parse(String(value)); } catch { return fallback; }
}

const built = $("A. Build Review Case Record").first().json || {};
const baseCase = built.review_case || {};
const config = built.config || {};

return items.map(item => {
  const row = item.json || {};
  const rc = {
    ...baseCase,
    ...row,
    template_variables: parseJson(row.template_variables, baseCase.template_variables || {}),
    blocked_variables: parseJson(row.blocked_variables, baseCase.blocked_variables || []),
    sanitized_context: parseJson(row.sanitized_context, baseCase.sanitized_context || {}),
    decision_payload: parseJson(row.decision_payload, baseCase.decision_payload || null)
  };

  const ctx = rc.sanitized_context || {};
  const base = String((config.review || {}).review_base_url || "").replace(/\/$/, "");
  const reviewUrl = base + "/review?case=" + encodeURIComponent(rc.case_id || "") + "&token=" + encodeURIComponent(rc.token || "");
  const snippet = String(ctx.reply_snippet || ctx.reply_text || "").slice(0, 200);

  const lines = [];
  lines.push("New reply review case: " + (rc.case_id || "UNKNOWN_CASE"));
  lines.push("Category: " + (ctx.category || rc.category || "UNKNOWN") + " | Urgency: " + (ctx.urgency || rc.urgency || "routine"));
  lines.push("Reply excerpt: " + snippet);
  lines.push("Review: " + reviewUrl);

  return {
    json: {
      ...built,
      review_case: rc,
      chat_notification: {
        payload: { text: lines.join("\n") },
        review_url: reviewUrl
      }
    }
  };
});

