function getBranchContext() {
  try {
    const item = $("D. Build Google Chat Notification Payload").first();
    if (item && item.json) return item.json;
  } catch {}
  try {
    const item = $("D2. Mark Review Notification Failed").first();
    if (item && item.json) return item.json;
  } catch {}
  return {};
}

const branchContext = getBranchContext();

return items.map(item => {
  const response = item.json || {};
  const input = { ...branchContext, chat_delivery_response: response };
  if (response.error) input.error = response.error;

  const rc = { ...(input.review_case || {}) };
  if (rc.notification_status === "PENDING") {
    const sentOk = !!(
      input.chat_notification &&
      input.chat_notification.review_url &&
      !input.chat_notification.skipped_reason &&
      !input.error
    );
    rc.notification_status = sentOk ? "SENT" : "REVIEW_NOTIFICATION_FAILED";
  }
  rc.updated_at = new Date().toISOString();

  return { json: { ...input, review_case: rc } };
});

