  } : null;

  const handoff = row && row.sanitized_context && row.sanitized_context.sender_handoff
    ? row.sanitized_context.sender_handoff
    : null;

  let tokenValid = true;
  let reason = "OK";

  if (!row) { tokenValid = false; reason = "CASE_NOT_FOUND"; }
  else if (!token || row.token !== token) { tokenValid = false; reason = "WRONG_TOKEN"; }
  else if (row.status !== "NEW" && row.status !== "IN_REVIEW") { tokenValid = false; reason = "ALREADY_DECIDED"; }
  else if (row.token_expires_at && new Date(row.token_expires_at).getTime() < Date.now()) { tokenValid = false; reason = "EXPIRED"; }
  else if (!handoff || !handoff.nes || !handoff.decision || !handoff.validation) { tokenValid = false; reason = "MISSING_SENDER_HANDOFF"; }

  return {
    json: {
      ...webhook,
      case_id: caseId,
      token,
      token_valid: tokenValid,
      token_invalid_reason: reason,
      review_case: row || {},
      case_input: handoff || {},
